namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private DbContextOptions<SchoolContext> _options;

    [TestInitialize]
    public void Setup()
    {
        _options = TestDbContextFactory.CreateOptions();
        // Drain the static notification queue to avoid interference
        var drainer = new NotificationService();
        while (drainer.ReceiveNotification() != null) { }
    }

    private NotificationsController CreateController(SchoolContext context)
    {
        var controller = new NotificationsController(context);
        ControllerTestHelper.SetupController(controller);
        return controller;
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);

        // Act
        var result = controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);

        // Act
        var result = controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
        var value = result.Value;
        Assert.IsNotNull(value);
        // Verify it contains success = true by checking the anonymous object
        var type = value.GetType();
        var successProp = type.GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
        var countProp = type.GetProperty("count");
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);
        // Enqueue some notifications via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "Admin");
        service.SendNotification("Course", "2", "Chemistry", EntityOperation.UPDATE, "Admin");

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        var type = value.GetType();
        var successProp = type.GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
        var countProp = type.GetProperty("count");
        Assert.AreEqual(2, countProp.GetValue(value));
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);

        // Act
        var result = controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
        var value = result.Value;
        var type = value.GetType();
        var successProp = type.GetProperty("success");
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);
        var service = new NotificationService();
        // Enqueue 15 notifications
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), $"Item {i}", EntityOperation.CREATE, "Admin");
        }

        // Act
        var result = controller.GetNotifications();

        // Assert
        var value = result.Value;
        var type = value.GetType();
        var countProp = type.GetProperty("count");
        Assert.AreEqual(10, countProp.GetValue(value)); // Limited to 10
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var list = new PaginatedList<string>(new List<string> { "a", "b" }, 10, 3, 5);

        // Assert
        Assert.AreEqual(3, list.PageIndex);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
    [DataRow(1, 5, 1, DisplayName = "1 item, page size 5 = 1 page")]
    [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 = 0 pages")]
    [DataRow(5, 5, 1, DisplayName = "5 items, page size 5 = 1 page")]
    public void Constructor_CalculatesTotalPages(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var list = new PaginatedList<string>(new List<string>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<int> { 1, 2, 3 };

        // Act
        var list = new PaginatedList<int>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(1, list[0]);
        Assert.AreEqual(2, list[1]);
        Assert.AreEqual(3, list[2]);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Assert
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Assert - page 2 of 2 total pages
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // Arrange
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Assert - page 1 of 2 total pages
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]); // Second page starts at item 6
        Assert.AreEqual(10, result[4]); // Ends at item 10
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPartialPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(2, result.TotalPages);
        Assert.AreEqual(2, result.Count); // Only 2 items on last page
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
    }

    [TestMethod]
    public void HasPreviousPage_PageZero_ReturnsFalse()
    {
        // Arrange - edge case with page index 0
        var list = new PaginatedList<string>(new List<string>(), 10, 0, 5);

        // Assert
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_PageBeyondTotal_ReturnsFalse()
    {
        // Arrange - edge case where page index equals total pages
        var list = new PaginatedList<string>(new List<string>(), 5, 1, 5);

        // Assert - TotalPages = 1, PageIndex = 1 => not less than
        Assert.IsFalse(list.HasNextPage);
    }
}

