using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        // Drain the static queue to avoid interference between tests
        var drainer = new NotificationService();
        while (drainer.ReceiveNotification() != null) { }
        _sut = new NotificationService();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.IsNotNull(received);
        Assert.AreEqual("Student", received.EntityType);
        Assert.AreEqual("1", received.EntityId);
        Assert.AreEqual("CREATE", received.Operation);
        Assert.AreEqual("TestUser", received.CreatedBy);
        Assert.IsFalse(received.IsRead);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        // Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.IsNotNull(received);
        Assert.AreEqual("New Course 'Chemistry' has been created", received.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "101", EntityOperation.CREATE, "Admin");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.IsNotNull(received);
        Assert.AreEqual("New Course (ID: 101) has been created", received.Message);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "5", "John Smith", EntityOperation.CREATE);

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("New Student 'John Smith' has been created", received.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Department", "3", "Engineering", EntityOperation.UPDATE);

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been updated", received.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Instructor", "7", "Jane Doe", EntityOperation.DELETE);

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("Instructor 'Jane Doe' has been deleted", received.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now;

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var received = _sut.ReceiveNotification();
        var after = DateTime.Now;
        Assert.IsTrue(received.CreatedAt >= before && received.CreatedAt <= after,
            $"CreatedAt {received.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("System", received.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "AdminUser");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("AdminUser", received.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInOrder()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", "Second", EntityOperation.CREATE);
        _sut.SendNotification("Student", "3", "Third", EntityOperation.CREATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.AreEqual("3", third.EntityId);

        var empty = _sut.ReceiveNotification();
        Assert.IsNull(empty);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should not throw
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", null, EntityOperation.UPDATE, "Admin");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been updated", received.Message);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", "", EntityOperation.DELETE, "Admin");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been deleted", received.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", "   ", EntityOperation.CREATE, "Admin");

        // Assert
        var received = _sut.ReceiveNotification();
        Assert.AreEqual("New Student (ID: 42) has been created", received.Message);
    }
}

