namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private DbContextOptions<SchoolContext> _options;

    [TestInitialize]
    public void Setup()
    {
        _options = TestDbContextFactory.CreateOptions();
    }

    private InstructorsController CreateController(SchoolContext context)
    {
        var controller = new InstructorsController(context);
        ControllerTestHelper.SetupController(controller);
        return controller;
    }

    private void SeedInstructorsWithCourses(DbContextOptions<SchoolContext> options)
    {
        using var seedContext = new SchoolContext(options);

        var instructor1 = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };
        var instructor2 = new Instructor
        {
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };
        seedContext.Instructors.AddRange(instructor1, instructor2);
        seedContext.SaveChanges();

        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000m,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        seedContext.Departments.Add(dept);
        seedContext.SaveChanges();

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>()
        };
        seedContext.Courses.Add(course);
        seedContext.SaveChanges();

        seedContext.CourseAssignments.Add(new CourseAssignment
        {
            CourseID = 1050,
            InstructorID = instructor1.ID
        });
        seedContext.SaveChanges();
    }

    private void SeedSimpleInstructor(DbContextOptions<SchoolContext> options)
    {
        using var seedContext = new SchoolContext(options);
        seedContext.Instructors.Add(new Instructor
        {
            LastName = "TestInstructor",
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2020-01-01"),
            CourseAssignments = new List<CourseAssignment>()
        });
        seedContext.SaveChanges();
    }

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        // Arrange
        SeedInstructorsWithCourses(_options);
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Instructors);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_EmptyDatabase_ReturnsEmptyInstructors()
    {
        // Arrange
        using var context = new SchoolContext(_options);
        var controller = CreateController(context);

        // Act
        var result = controller.Index(null, null) as ViewResult;

